const output = $input.first().json.output || $input.first().json.text || '';
let parsed = {};

try {
  // Find JSON in the AI response
  let text = output;
  let s = text.indexOf("{");
  let e = text.lastIndexOf("}");
  if (s !== -1 && e > s) {
    parsed = JSON.parse(text.substring(s, e + 1));
  }
} catch(err) {
  // Try double-decode
  try {
    let inner = JSON.parse(output);
    if (typeof inner === "string") parsed = JSON.parse(inner);
    else parsed = inner;
  } catch(e2) {}
}

// Helper: get field case-insensitively
const g = (field) => parsed[field] || parsed[field.toUpperCase()] || parsed[field.toLowerCase()] || '';

return [{
  json: {
    timestamp: new Date().toISOString(),
    customer_id: String(g('customer_id') || 'N/A'),
    topic: String(g('topic') || ''),
    sentiment: String(g('sentiment') || ''),
    sentiment_score: String(g('sentiment_score') || ''),
    urgency: String(g('urgency') || ''),
    churn_risk: String(g('churn_risk') || ''),
    revenue_impact: String(g('revenue_impact') || ''),
    recommended_template: String(g('recommended_template') || ''),
    recommended_action: String(g('recommended_action') || ''),
    escalate_to: Array.isArray(g('escalate_to')) ? g('escalate_to').join(', ') : String(g('escalate_to') || ''),
    personalized_response: String(g('personalized_response') || ''),
    upsell_opportunity: String(g('upsell_opportunity') || ''),
    root_cause: String(g('root_cause') || ''),
    confidence: String(g('confidence') || '0.85'),
    key_phrases: Array.isArray(g('key_phrases')) ? g('key_phrases').join(', ') : String(g('key_phrases') || ''),
    processed_by: 'Campaign Copilot AI Agent v1.0'
  }
}];
